import { ListViewTable } from '@gfazioli/mantine-list-view-table';
import { Table } from '@mantine/core';
import { data, columns } from './data';

function Demo() {
  return (
    <Table.ScrollContainer minWidth={500}>
      <ListViewTable
        columns={columns}
        data={data}
        rowKey="id"
        withTableBorder
        withColumnBorders
        highlightOnHover
        enableColumnResizing
      />
    </Table.ScrollContainer>
  );
}
