import type { ListViewTableColumn } from '@gfazioli/mantine-list-view-table';

export const columns: ListViewTableColumn[] = [
  {
    key: 'name',
    title: 'Name (Header: noWrap, Cell: wrap)',
    sortable: true,
    noWrap: true,
    ellipsis: false,
    cellStyle: {
      whiteSpace: 'normal',
      textOverflow: 'ellipsis',
      overflow: 'hidden',
      lineHeight: '1.2em',
    },
  },
  {
    key: 'description',
    title: 'Description (Header: ellipsis, Cell: wrap)',
    sortable: true,
    ellipsis: true,
    noWrap: true,
    cellStyle: {
      whiteSpace: 'normal',
      textOverflow: 'clip',
      overflow: 'visible',
      lineHeight: '1.2em',
    },
  },
  {
    key: 'modified',
    title: 'Modified (dynamic cellStyle)',
    sortable: true,
    width: 120,
    ellipsis: true,
    noWrap: true,
    cellStyle: (record) => ({
      backgroundColor:
        record.type === 'folder' ? 'var(--mantine-color-blue-0)' : 'var(--mantine-color-gray-0)',
      fontWeight: record.type === 'folder' ? 600 : 400,
      padding: '8px 12px',
      borderRadius: '4px',
    }),
  },
];
